import{_ as t,c as s,a as l,o as a}from"./app-CLrBGaZw.js";const i={};function r(c,e){return a(),s("div",null,e[0]||(e[0]=[l('<h1 id="react面试题" tabindex="-1"><a class="header-anchor" href="#react面试题"><span>React面试题</span></a></h1><h2 id="super-和-super-props-有什么区别" tabindex="-1"><a class="header-anchor" href="#super-和-super-props-有什么区别"><span>super() 和 super(props) 有什么区别？</span></a></h2><blockquote><p>super 关键字实现调用父类，super 代替的是父类的构建函数，使用 super(name) 相当于调用 sup.prototype.constructor.call(this,name)</p></blockquote><p>类式组件中会有这种写法</p><h2 id="说说react-render方法的原理-在什么时候会被触发" tabindex="-1"><a class="header-anchor" href="#说说react-render方法的原理-在什么时候会被触发"><span>说说React render方法的原理？在什么时候会被触发？</span></a></h2><p>render函数在react里面有两种形式。</p><ul><li>类式组件 指的是render方法</li><li>函数式组件 指的是函数本身</li></ul><h2 id="触发时机" tabindex="-1"><a class="header-anchor" href="#触发时机"><span>触发时机</span></a></h2><ul><li>组件初始构建</li><li>类组件调用setState修改状态</li><li>函数组件通过useState hook改变状态</li><li>类组件重新渲染</li><li>函数组件重新渲染</li></ul><h2 id="常用的hooks" tabindex="-1"><a class="header-anchor" href="#常用的hooks"><span>常用的Hooks</span></a></h2><ul><li>useEffect 让函数式组件可以处理副作用(与UI渲染无关的一切代码)，并且可以模拟 componentDidMount，componentDidUpdate、compentWillUnMount等生命周期 执行机制 <ul><li>触发时机：useEffect 的触发时机依赖于提供的依赖数组。如果依赖数组为空，那么 useEffect 将在每次渲染后执行。如果依赖数组包含变量，那么 useEffect 将在这些变量发生变化时执行。</li><li>执行顺序：在每次组件渲染后，React 会按照 useEffect 钩子的出现顺序来执行它们。如果某个 useEffect 依赖于另一个 useEffect 的输出，那么先执行依赖的 useEffect。</li><li>清理：当 useEffect 执行完毕后，React 会自动清理其副作用，比如取消订阅、清除定时器等。</li><li>错误处理：如果在 useEffect 的执行过程中抛出错误，React 会捕获这个错误并打印一条错误消息。</li><li>性能优化：React 会根据 useEffect 的依赖数组来决定是否需要重新执行。如果依赖数组中的变量没有发生变化，那么 React 不会重新执行 useEffect。这有助于减少不必要的操作，提高应用的性能。 <strong>注意点：尽管 useEffect 在每次组件渲染后都会执行，但 React 不会在每次渲染后都重新创建 useEffect 的回调函数。这意味着如果你在回调函数中使用了闭包，那么这些闭包会在整个组件生命周期内保持不变。因此，在回调函数中使用的所有变量都必须是状态的一部分或者是在组件中不变的。</strong></li></ul></li><li>useState 用于设置函数式组件的状态，在状态更新的时候(setXXX)会进行浅比较，当更新的状态值与当前状态值相同的则不会触发更新。</li><li>useRef 主要用于获取dom对象，获取子组件的实例，记录非状态数据用来持久化数据</li><li>useMemo 与vue中的computed相似，接受一个计算函数以及依赖项，只有当依赖项改变的时候才会重新执行计算函数，否则将用上次缓存的结果。</li><li>useReducer 类似Redux</li><li>useLayoutEffect useLayoutEffect与useEffect用法相似，主要区别是它是在渲染前(此时Dom已经根据VDom进行了修改，但是还没有渲染呈现到屏幕上)同步执行的</li><li>useCallback 用于在2次渲染间保存函数实例，防止多次渲染造成的函数重新创建，一般只在需要将函数作为 props 传递给子组件或将其作为依赖项传递给其他 Hook 时，才需要考虑使用 useCallback 进行优化</li></ul>',11)]))}const u=t(i,[["render",r],["__file","index.html.vue"]]),n=JSON.parse('{"path":"/tools/docs/interview/React/%E7%94%9F%E5%91%BD%E5%91%A8%E6%9C%9F/","title":"React面试题","lang":"zh-CN","frontmatter":{},"headers":[{"level":2,"title":"super() 和 super(props) 有什么区别？","slug":"super-和-super-props-有什么区别","link":"#super-和-super-props-有什么区别","children":[]},{"level":2,"title":"说说React render方法的原理？在什么时候会被触发？","slug":"说说react-render方法的原理-在什么时候会被触发","link":"#说说react-render方法的原理-在什么时候会被触发","children":[]},{"level":2,"title":"触发时机","slug":"触发时机","link":"#触发时机","children":[]},{"level":2,"title":"常用的Hooks","slug":"常用的hooks","link":"#常用的hooks","children":[]}],"git":{"updatedTime":1739848913000,"contributors":[{"name":"LiHegui","username":"LiHegui","email":"1487647822@qq.com","commits":2,"url":"https://github.com/LiHegui"}]},"filePathRelative":"tools/docs/interview/React/生命周期/index.md"}');export{u as comp,n as data};
